import os

def delete_uploaded_file(filename, uploads_dir="uploads"):
    safe_name = os.path.basename(filename)
    file_path = os.path.join(uploads_dir, safe_name)

    if not os.path.isfile(file_path):
        return False

    os.remove(file_path)
    return True